import{_ as s,o as e,c as i,a5 as l}from"./chunks/framework.B5tqjWbr.js";const k=JSON.parse('{"title":"概念：单相 SRF-PLL 入门","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：单相 SRF-PLL 入门","tags":["power-electronics"],"status":"learning","summary":"锁相环（phase-locked loop / PLL）是一个估算电网相位和频率的闭环。同步旋转坐标系（synchronous reference frame / SRF）PLL 的核心想法是：把输入电压投影到自己估计的旋转坐标系里，让 q 轴误差（q-axis error / vq）趋近于 0。"},"headers":[],"relativePath":"content/power/concepts/control/single-phase-srf-pll.md","filePath":"content/power/concepts/control/single-phase-srf-pll.md","lastUpdated":null}'),t={name:"content/power/concepts/control/single-phase-srf-pll.md"};function n(p,a,o,h,r,c){return e(),i("div",null,[...a[0]||(a[0]=[l(`<h1 id="概念-单相-srf-pll-入门" tabindex="-1">概念：单相 SRF-PLL 入门 <a class="header-anchor" href="#概念-单相-srf-pll-入门" aria-label="Permalink to &quot;概念：单相 SRF-PLL 入门&quot;">​</a></h1><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>锁相环（phase-locked loop / PLL）是一个估算电网相位和频率的闭环。同步旋转坐标系（synchronous reference frame / SRF）PLL 的核心想法是：把输入电压投影到自己估计的旋转坐标系里，让 q 轴误差（q-axis error / vq）趋近于 0。</p><p>本节只讲一个概念：<code>vq</code> 不为 0 时，说明估算相位和真实电网相位有误差；用比例积分控制器（proportional-integral controller / PI）修正估算频率，积分后得到新的相位。</p><p>保密边界：不能记录公司内部代码、未公开产品方案、客户项目参数、内部测试数据。本节只使用教学模型和教学参数，不包含公司内部代码、未公开产品方案、客户项目参数或内部测试数据。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）需要知道电网相位：</p><ul><li>功率因数校正（power factor correction / PFC）要让输入电流参考和电网电压同相。</li><li>旁路（bypass）切换需要判断逆变输出和电网是否同步。</li><li>逆变器并网或跟随旁路时，需要相位、频率和相序信息。</li></ul><p>如果 PLL 错，相当于“坐标系错了”。后面的电流参考、功率方向、并联系统同步都会受影响。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>把 PLL 想成一个追着电网转的指针。指针慢了，电网相位会跑到前面；指针快了，会超过电网。<code>vq</code> 就像“偏左还是偏右”的误差信号。PI 控制器根据这个误差调快或调慢指针，直到指针和电网相位对齐。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>教学模型使用相位误差直接构造 q 轴误差：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>theta_err = theta_grid - theta_hat</span></span>
<span class="line"><span>vq = sin(theta_err)</span></span>
<span class="line"><span>omega_hat = omega_nominal + Kp * vq + integral(Ki * vq)</span></span>
<span class="line"><span>theta_hat[k+1] = theta_hat[k] + omega_hat * Ts</span></span></code></pre></div><p>当误差很小时：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>sin(theta_err) ≈ theta_err</span></span></code></pre></div><p>所以 PLL 在锁定附近可以近似看成一个二阶闭环。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_srf_pll.py</span></span></code></pre></div><p>观察：</p><ul><li>初始相位误差会被 PLL 拉回 0 附近。</li><li>60 ms 时电网相位阶跃 30 度，<code>theta_err</code> 会突然变大。</li><li><code>f_est</code> 会短时升高，表示 PLL 让估算相位追上电网。</li><li>锁定后相位误差回到 ±5 度附近，估算频率回到 50 Hz 附近。</li></ul><p>一个仿真任务：对比慢 PLL 和快 PLL 的相位收敛速度、估算频率（estimated frequency / f_est）动作幅度。</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_srf_pll.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">kp </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">80</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ki </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3000</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\srf_pll_slow.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\single_phase_srf_pll.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">kp </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">260</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ki </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">22000</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">output simulations\\results\\srf_pll_fast.png </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>固件里 PLL 通常在固定采样周期运行：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ADC voltage sample</span></span>
<span class="line"><span>  -&gt; scaling/filtering</span></span>
<span class="line"><span>  -&gt; phase detector, vq</span></span>
<span class="line"><span>  -&gt; PI loop filter</span></span>
<span class="line"><span>  -&gt; frequency limit</span></span>
<span class="line"><span>  -&gt; phase accumulator</span></span>
<span class="line"><span>  -&gt; sin/cos angle output</span></span></code></pre></div><p>落地时要注意：</p><ul><li>输入电压要有幅值归一化或滤波，否则电网幅值变化会干扰相位检测。</li><li>估算频率要限幅，避免采样异常时相位飞掉。</li><li>PLL 输出的角度会被 PFC 电流参考、旁路同步和逆变控制复用。</li><li>锁定判据不能只看瞬间误差，要看一段时间内的相位误差和频率误差。</li></ul><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>错误理解：PLL 只是过零检测。<br> 正确理解：过零检测只能粗略给相位点，PLL 是连续估算相位和频率的闭环。</p></li><li><p>错误理解：PLL 越快越好。<br> 正确理解：太快会把电网噪声、谐波和采样毛刺带进角度；太慢会跟不上频率和相位变化。</p></li><li><p>错误理解：PFC 不需要 PLL。<br> 正确理解：简单单相 PFC 可以直接用电压采样生成参考，但工程里仍常需要相位、频率、过零、同步和异常检测信息。</p></li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li>能解释 <code>vq</code> 为什么代表估算相位偏差。</li><li>能说明 <code>omega_hat</code> 如何由额定角频率、比例项和积分项组成。</li><li>能在图中指出 <code>vac</code>、<code>theta_err</code>、<code>vq</code>、<code>f_est</code> 和锁定带（lock band）。</li><li>能解释相位阶跃后 <code>f_est</code> 为什么会短时升高。</li><li>能基于 <code>single_phase_srf_pll.py</code> 生成的仿真图准备导师问题。</li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li>为什么 <code>theta_err</code> 回到 0 附近时，<code>vq</code> 也会回到 0 附近？</li><li>如果把 <code>--kp</code> 和 <code>--ki</code> 调得很大，图里的 <code>f_est</code> 会出现什么变化？</li><li>如果输入电网电压含 5 次谐波，PLL 角度可能会怎样受影响？</li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li>我用 <code>single_phase_srf_pll.py</code> 看到 30 度相位阶跃后，<code>f_est</code> 会短时升高再回到 50 Hz。公司 UPS 的 PLL 锁定判据通常看相位误差、频率误差，还是两者都看？</li><li>图里 <code>Kp=180, Ki=12000</code> 能较快收敛。实际工程中 PLL 带宽通常如何选，PFC 和旁路同步会不会用不同带宽？</li><li>如果输入电压含谐波或采样噪声，公司平台是在 PLL 前加滤波，还是在 <code>vq</code> 误差后加滤波？</li></ul>`,37)])])}const u=s(t,[["render",n]]);export{k as __pageData,u as default};
